// Enhanced scheduling assistant with Calendar Manager integration
app.on('message', async ({ send, activity }) => {
  const userMessage = activity.text?.toLowerCase() || '';
  
  await send({ type: 'typing' });
  
  // Check if this is a calendar-related request that should go to Calendar Manager
  const calendarKeywords = ['schedule', 'meeting', 'calendar', 'appointment', 'book', 'free', 'busy', 'available'];
  const isCalendarRequest = calendarKeywords.some(keyword => userMessage.includes(keyword));
  
  if (isCalendarRequest) {
    // Forward to Calendar Manager for real processing
    const calendarResponse = await forwardToCalendarManager(activity.text || '');
    await send(calendarResponse);
    return;
  }
  
  // Greetings and introductions
  if (userMessage.includes('hello') || userMessage.includes('hi') || userMessage.includes('hey')) {
    await send(`👋 **Hello! I'm your Multi-Agent AI Scheduling Assistant!**

🤖 **I'm now connected to the real Calendar Manager!**

Here's what I can do with the Calendar Manager integration:

🗓️ **Real Calendar Operations**
└ "Schedule a meeting for 4pm tomorrow"
└ "What's my schedule today?"
└ "Book a 2-hour workshop next Friday"
└ "Cancel my 3pm meeting"

📋 **Live Calendar Access**  
└ Connected to Microsoft 365 Calendar
└ Real-time availability checking
└ Actual meeting creation and updates

⚡ **Powered by Copilot Studio Calendar Manager**
└ Environment: ${CALENDAR_MANAGER_CONFIG.environmentId.substring(0, 8)}...
└ Bot: ${CALENDAR_MANAGER_CONFIG.schemaName}

**Try a real calendar request!** I'll forward it to the Calendar Manager for actual processing. ✨`);
    return;
  }
  
  // Help and capabilities
  if (userMessage.includes('help') || userMessage.includes('what can you do')) {
    await send(`🤖 **Multi-Agent AI Scheduling Assistant - Help**

**🔗 Connected to Calendar Manager:**
• Environment: ${CALENDAR_MANAGER_CONFIG.environmentId.substring(0, 8)}...
• Bot: ${CALENDAR_MANAGER_CONFIG.schemaName}

**Real Calendar Commands:**
• "Schedule a meeting for 4pm tomorrow"
• "Show my calendar for today"  
• "When am I free this week?"
• "Cancel my 2pm meeting"
• "Reschedule meeting to 3pm"

**Calendar Manager Features:**
✅ Real Microsoft 365 calendar integration
✅ Live availability checking
✅ Actual meeting creation and invites
✅ Conflict detection and resolution
✅ Teams meeting link generation

**How it works:**
1. You ask for calendar help
2. I forward your request to Calendar Manager
3. Calendar Manager processes with real calendar APIs
4. You get actual calendar results!

Just tell me what you need - I'll connect you to the real Calendar Manager! �`);
    return;
  }
  
  // Default response with Calendar Manager info
  await send(`🤖 **Multi-Agent Scheduling Assistant**

📨 **You said:** "${activity.text}"

🔗 **I'm connected to the real Calendar Manager!**

**For calendar requests, try:**
• "Schedule a meeting for tomorrow at 4pm"
• "What's my schedule today?"
• "When am I free this week?"

**Calendar Manager Info:**
• 🌐 Environment: ${CALENDAR_MANAGER_CONFIG.environmentId.substring(0, 8)}...
• 🤖 Bot: ${CALENDAR_MANAGER_CONFIG.schemaName}
• ⚡ Status: Ready for real calendar operations

I'll forward any calendar-related requests to the Calendar Manager for actual processing! �`);
});

(async () => {
  // Initialize Calendar Manager connection
  await initializeCalendarManager();
  
  // Start the application
  await app.start(+(process.env.PORT || 3978));
  console.log('🤖 Multi-Agent AI Scheduling Assistant is running on port', process.env.PORT || 3978);
  console.log('🌐 DevTools available at: http://localhost:3979/devtools');
  console.log('🔗 Connected to Calendar Manager:', CALENDAR_MANAGER_CONFIG.schemaName);
})();
